// ---------------------------------------------------------------------------
// Lookup helpers
// ---------------------------------------------------------------------------

const _byCategory = new Map<string, Product[]>();
const _byVendor = new Map<string, Product[]>();
const _byId = new Map<string, Product>();

for (const p of PRODUCTS) {
  _byId.set(p.id, p);
  if (p.categoryCode) {
    const arr = _byCategory.get(p.categoryCode) ?? [];
    arr.push(p);
    _byCategory.set(p.categoryCode, arr);
  }
  const vArr = _byVendor.get(p.vendor) ?? [];
  vArr.push(p);
  _byVendor.set(p.vendor, vArr);
}

export function getProductById(id: string): Product | undefined { return _byId.get(id); }
export function getProductsByCategory(code: string): Product[] { return _byCategory.get(code) ?? []; }
export function getProductsByVendor(vendor: string): Product[] { return _byVendor.get(vendor) ?? []; }
export function getAllCategories(): string[] { return Array.from(_byCategory.keys()); }
export function getAllVendors(): string[] { return Array.from(_byVendor.keys()); }

export function getProductsByPriceTier(code: string, tier: PriceTier): Product[] {
  return getProductsByCategory(code).filter(p => p.priceTier === tier);
}

export function getTopRatedProducts(code: string, limit = 5): Product[] {
  return getProductsByCategory(code)
    .filter(p => p.rating !== null && p.ratingCount >= 3)
    .sort((a, b) => {
      const scoreA = (a.rating ?? 0) * Math.log2((a.ratingCount || 1) + 1);
      const scoreB = (b.rating ?? 0) * Math.log2((b.ratingCount || 1) + 1);
      return scoreB - scoreA;
    })
    .slice(0, limit);
}

